{
  "$schema": "https://nativeui.qzz.io/schema/registry-item.json",
  "name": "accordion",
  "type": "registry:component",
  "title": "Accordion",
  "description": "Accordion component",
  "registryDependencies": [],
  "dependencies": [
    "@expo/vector-icons/AntDesign",
    "@rn-primitives/accordion",
    "react-native-reanimated"
  ],
  "category": "layout",
  "files": [
    {
      "path": "components/ui/accordion.tsx",
      "type": "registry:component",
      "target": "components/ui/accordion.tsx",
      "content": "import { THEME, useTheme } from "@/lib/theme";
import AntDesign from "@expo/vector-icons/AntDesign";
import * as AccordionPrimitive from "@rn-primitives/accordion";
import * as React from "react";
import { type LayoutChangeEvent, Pressable, Text, View } from "react-native";
import Animated, { Easing, useAnimatedStyle, useDerivedValue, useSharedValue, withTiming, } from "react-native-reanimated";
const Accordion = React.forwardRef<React.ElementRef<typeof AccordionPrimitive.Root>, React.ComponentPropsWithoutRef<typeof AccordionPrimitive.Root>>(({ children, style, ...props }, ref) => {
    return (<AccordionPrimitive.Root ref={ref} {...props} asChild>
      <View style={[{ width: "100%" }, style]}>{children}</View>
    </AccordionPrimitive.Root>);
});
Accordion.displayName = "Accordion";
const AccordionItem = React.forwardRef<React.ElementRef<typeof AccordionPrimitive.Item>, React.ComponentPropsWithoutRef<typeof AccordionPrimitive.Item>>(({ children, style, value, ...props }, ref) => {
    const { theme } = useTheme();
    const { colors } = THEME[theme];
    return (<AccordionPrimitive.Item ref={ref} value={value} {...props} asChild>
      <View style={[
            {
                borderBottomWidth: 1,
                borderBottomColor: colors.border,
                overflow: "hidden",
            },
            style,
        ]}>
        {children}
      </View>
    </AccordionPrimitive.Item>);
});
AccordionItem.displayName = "AccordionItem";
const AccordionTrigger = React.forwardRef<React.ElementRef<typeof Pressable>, Omit<React.ComponentPropsWithoutRef<typeof AccordionPrimitive.Trigger>, "children"> & {
    children?: React.ReactNode;
}>(({ children, style, ...props }, ref) => {
    const { isExpanded, disabled } = AccordionPrimitive.useItemContext();
    const { theme } = useTheme();
    const { colors, spacing, typography } = THEME[theme];
    const progress = useDerivedValue(() => isExpanded
        ? withTiming(1, { duration: 250 })
        : withTiming(0, { duration: 200 }));
    const chevronStyle = useAnimatedStyle(() => ({
        transform: [{ rotate: `${progress.value * 180}deg` }],
    }));
    return (<AccordionPrimitive.Header asChild>
      <View>
        <AccordionPrimitive.Trigger ref={ref} {...props} asChild>
          <Pressable style={(state) => [
            {
                flexDirection: "row",
                alignItems: "center",
                justifyContent: "space-between",
                paddingVertical: spacing.md,
                gap: spacing.sm,
                opacity: state.pressed || disabled ? 0.6 : 1,
            },
            typeof style === "function" ? style(state) : style,
        ]}>
            <View style={{ flex: 1 }}>
              {typeof children === "string" ? (<Text style={{
                fontSize: typography.base,
                fontWeight: "500",
                color: colors.foreground,
            }}>
                  {children}
                </Text>) : (children)}
            </View>

            <Animated.View style={chevronStyle}>
              <AntDesign name="down" size={18} color={colors.mutedForeground}/>
            </Animated.View>
          </Pressable>
        </AccordionPrimitive.Trigger>
      </View>
    </AccordionPrimitive.Header>);
});
AccordionTrigger.displayName = "AccordionTrigger";
const AccordionContent = React.forwardRef<React.ElementRef<typeof AccordionPrimitive.Content>, React.ComponentPropsWithoutRef<typeof AccordionPrimitive.Content>>(({ children, style, ...props }, ref) => {
    const { isExpanded } = AccordionPrimitive.useItemContext();
    const { theme } = useTheme();
    const { colors, spacing, typography } = THEME[theme];
    const [measuredHeight, setMeasuredHeight] = React.useState(0);
    const animatedHeight = useSharedValue(0);
    React.useEffect(() => {
        if (measuredHeight > 0) {
            animatedHeight.value = withTiming(isExpanded ? measuredHeight : 0, {
                duration: 250,
                easing: Easing.out(Easing.ease),
            });
        }
    }, [isExpanded, measuredHeight]);
    const handleLayout = React.useCallback((e: LayoutChangeEvent) => {
        const h = Math.ceil(e.nativeEvent.layout.height);
        if (h > 0 && h !== measuredHeight) {
            setMeasuredHeight(h);
            if (isExpanded && measuredHeight === 0) {
                animatedHeight.value = h;
            }
        }
    }, [measuredHeight, isExpanded]);
    const animStyle = useAnimatedStyle(() => ({
        height: measuredHeight === 0 ? 0 : animatedHeight.value,
        opacity: measuredHeight === 0
            ? 0
            : withTiming(isExpanded ? 1 : 0, { duration: 250 }),
    }));
    return (<AccordionPrimitive.Content ref={ref} {...props} forceMount asChild>
      <Animated.View style={[{ overflow: "hidden", width: "100%" }, animStyle]}>
        <View onLayout={handleLayout} style={[
            { paddingBottom: spacing.md },
            { position: "absolute", top: 0, width: "100%" },
            style,
        ]}>
          {typeof children === "string" ? (<Text style={{
                fontSize: typography.sm,
                color: colors.mutedForeground,
                lineHeight: typography.sm * 1.6,
            }}>
              {children}
            </Text>) : (children)}
        </View>
      </Animated.View>
    </AccordionPrimitive.Content>);
});
AccordionContent.displayName = "AccordionContent";
export { Accordion, AccordionContent, AccordionItem, AccordionTrigger };
export const AccordionPrimitiveWrapper = {
    Root: Accordion,
    Item: AccordionItem,
    Trigger: AccordionTrigger,
    Content: AccordionContent,
};"
    }
  ]
}

{
  "$schema": "https://nativeui.qzz.io/schema/registry-item.json",
  "name": "alert-dialog",
  "type": "registry:component",
  "title": "Alert Dialog",
  "description": "Alert Dialog component",
  "registryDependencies": [],
  "dependencies": [
    "@rn-primitives/alert-dialog",
    "react-native-reanimated",
    "react-native-screens"
  ],
  "category": "feedback",
  "files": [
    {
      "path": "components/ui/alert-dialog.tsx",
      "type": "registry:component",
      "target": "components/ui/alert-dialog.tsx",
      "content": "import { THEME, useTheme } from "@/lib/theme";
import * as AlertDialogPrimitive from "@rn-primitives/alert-dialog";
import * as React from "react";
import { Platform, StyleSheet, Text, View, type ViewProps } from "react-native";
import Animated, { FadeIn, FadeOut } from "react-native-reanimated";
import { FullWindowOverlay as RNFullWindowOverlay } from "react-native-screens";
const isNative = Platform.OS !== "web";
const AlertDialog = AlertDialogPrimitive.Root;
const AlertDialogTrigger = AlertDialogPrimitive.Trigger;
const AlertDialogPortal = AlertDialogPrimitive.Portal;
const FullWindowOverlay = Platform.OS === "ios" ? RNFullWindowOverlay : React.Fragment;
const AlertDialogOverlay = React.forwardRef<React.ElementRef<typeof AlertDialogPrimitive.Overlay>, React.ComponentPropsWithoutRef<typeof AlertDialogPrimitive.Overlay>>(({ children, style, ...props }, ref) => {
    const { theme } = useTheme();
    const { spacing } = THEME[theme];
    return (<FullWindowOverlay>
      <AlertDialogPrimitive.Overlay ref={ref} {...props} asChild={isNative}>
        <Animated.View entering={isNative ? FadeIn.duration(200) : undefined} exiting={isNative ? FadeOut.duration(200) : undefined} style={StyleSheet.flatten([
            StyleSheet.absoluteFill,
            {
                backgroundColor: "rgba(0, 0, 0, 0.5)",
                justifyContent: "center",
                alignItems: "center",
                padding: spacing.xl,
            },
            Platform.OS === "web" && ({ position: "fixed", zIndex: 50 } as any),
            style,
        ])}>
          {children}
        </Animated.View>
      </AlertDialogPrimitive.Overlay>
    </FullWindowOverlay>);
});
AlertDialogOverlay.displayName = "AlertDialogOverlay";
const AlertDialogContent = React.forwardRef<React.ElementRef<typeof AlertDialogPrimitive.Content>, React.ComponentPropsWithoutRef<typeof AlertDialogPrimitive.Content> & {
    portalHost?: string;
}>(({ children, style, portalHost, ...props }, ref) => {
    const { theme } = useTheme();
    const { colors, radius, spacing } = THEME[theme];
    const contentNode = (<AlertDialogPrimitive.Content ref={ref} {...props} asChild={isNative}>
      <Animated.View entering={isNative ? FadeIn.duration(200).delay(50) : undefined} exiting={isNative ? FadeOut.duration(150) : undefined} style={StyleSheet.flatten([
            {
                backgroundColor: colors.background,
                borderRadius: radius.lg,
                padding: spacing.xl,
                width: "100%",
                maxWidth: 400,
                borderWidth: 1,
                borderColor: colors.border,
                gap: spacing.md,
                ...Platform.select({
                    ios: {
                        shadowColor: "#000",
                        shadowOffset: { width: 0, height: 2 },
                        shadowOpacity: 0.1,
                        shadowRadius: 8,
                    },
                    android: { elevation: 5 },
                    web: {
                        boxShadow: "0px 2px 8px rgba(0,0,0,0.1)",
                        position: "fixed",
                        top: "50%",
                        left: "50%",
                        transform: "translate(-50%, -50%)",
                        zIndex: 51,
                    } as any,
                }),
            },
            style,
        ])}>
        {children}
      </Animated.View>
    </AlertDialogPrimitive.Content>);
    if (Platform.OS === "web") {
        return (<AlertDialogPortal hostName={portalHost}>
        <AlertDialogOverlay />
        {contentNode}
      </AlertDialogPortal>);
    }
    return (<AlertDialogPortal hostName={portalHost}>
      <AlertDialogOverlay>{contentNode}</AlertDialogOverlay>
    </AlertDialogPortal>);
});
AlertDialogContent.displayName = "AlertDialogContent";
const AlertDialogHeader = ({ style, ...props }: ViewProps) => {
    const { theme } = useTheme();
    const { spacing } = THEME[theme];
    return (<View style={StyleSheet.flatten([{ gap: spacing.sm }, style])} {...props}/>);
};
AlertDialogHeader.displayName = "AlertDialogHeader";
const AlertDialogFooter = ({ style, ...props }: ViewProps) => {
    const { theme } = useTheme();
    const { spacing } = THEME[theme];
    return (<View style={StyleSheet.flatten([
            {
                flexDirection: "row",
                justifyContent: "flex-end",
                alignItems: "center",
                gap: spacing.sm,
                marginTop: spacing.sm,
                flexWrap: "wrap",
            },
            style,
        ])} {...props}/>);
};
AlertDialogFooter.displayName = "AlertDialogFooter";
const AlertDialogTitle = React.forwardRef<React.ElementRef<typeof AlertDialogPrimitive.Title>, React.ComponentPropsWithoutRef<typeof AlertDialogPrimitive.Title>>(({ style, ...props }, ref) => {
    const { theme } = useTheme();
    const { colors, typography } = THEME[theme];
    return (<AlertDialogPrimitive.Title ref={ref} asChild>
      <Text style={StyleSheet.flatten([
            {
                fontSize: typography.lg,
                fontWeight: "600",
                color: colors.foreground,
            },
            style,
        ])} {...props}/>
    </AlertDialogPrimitive.Title>);
});
AlertDialogTitle.displayName = "AlertDialogTitle";
const AlertDialogDescription = React.forwardRef<React.ElementRef<typeof AlertDialogPrimitive.Description>, React.ComponentPropsWithoutRef<typeof AlertDialogPrimitive.Description>>(({ style, ...props }, ref) => {
    const { theme } = useTheme();
    const { colors, typography } = THEME[theme];
    return (<AlertDialogPrimitive.Description ref={ref} asChild>
      <Text style={StyleSheet.flatten([
            {
                fontSize: typography.sm,
                color: colors.mutedForeground,
                lineHeight: typography.sm * 1.5,
            },
            style,
        ])} {...props}/>
    </AlertDialogPrimitive.Description>);
});
AlertDialogDescription.displayName = "AlertDialogDescription";
const AlertDialogAction = React.forwardRef<React.ElementRef<typeof AlertDialogPrimitive.Action>, React.ComponentPropsWithoutRef<typeof AlertDialogPrimitive.Action>>(({ style, ...props }, ref) => (<AlertDialogPrimitive.Action ref={ref} style={StyleSheet.flatten([style]) as any} {...props}/>));
AlertDialogAction.displayName = "AlertDialogAction";
const AlertDialogCancel = React.forwardRef<React.ElementRef<typeof AlertDialogPrimitive.Cancel>, React.ComponentPropsWithoutRef<typeof AlertDialogPrimitive.Cancel>>(({ style, ...props }, ref) => (<AlertDialogPrimitive.Cancel ref={ref} style={StyleSheet.flatten([style]) as any} {...props}/>));
AlertDialogCancel.displayName = "AlertDialogCancel";
export { AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent, AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogOverlay, AlertDialogPortal, AlertDialogTitle, AlertDialogTrigger, };
export const AlertDialogPrimitiveWrapper = {
    Root: AlertDialog,
    Trigger: AlertDialogTrigger,
    Portal: AlertDialogPortal,
    Overlay: AlertDialogOverlay,
    Content: AlertDialogContent,
    Header: AlertDialogHeader,
    Footer: AlertDialogFooter,
    Title: AlertDialogTitle,
    Description: AlertDialogDescription,
    Action: AlertDialogAction,
    Cancel: AlertDialogCancel,
};"
    }
  ]
}

{
  "$schema": "https://nativeui.qzz.io/schema/registry-item.json",
  "name": "alert",
  "type": "registry:component",
  "title": "Alert",
  "description": "Alert component",
  "registryDependencies": [],
  "dependencies": [],
  "category": "feedback",
  "files": [
    {
      "path": "components/ui/alert.tsx",
      "type": "registry:component",
      "target": "components/ui/alert.tsx",
      "content": "import { THEME, useTheme } from "@/lib/theme";
import React, { forwardRef } from "react";
import { StyleProp, StyleSheet, Text, TextProps, TextStyle, View, ViewProps, ViewStyle, } from "react-native";
export type AlertVariant = "default" | "destructive" | "warning" | "success" | "info";
const VARIANT_PALETTE: Record<AlertVariant, {
    accent: string;
    bg: string;
    bgDark: string;
}> = {
    default: { accent: "#71717a", bg: "#fafafa", bgDark: "#18181b" },
    destructive: { accent: "#dc2626", bg: "#fff1f1", bgDark: "#2a0a0a" },
    warning: { accent: "#d97706", bg: "#fffbeb", bgDark: "#1c1500" },
    success: { accent: "#16a34a", bg: "#f0fdf4", bgDark: "#071a0e" },
    info: { accent: "#2563eb", bg: "#eff6ff", bgDark: "#040d1f" },
};
type AlertContextValue = {
    variant: AlertVariant;
    accentColor: string;
};
const AlertContext = React.createContext<AlertContextValue>({
    variant: "default",
    accentColor: VARIANT_PALETTE.default.accent,
});
const useAlertContext = () => React.useContext(AlertContext);
type AlertProps = ViewProps & {
    variant?: AlertVariant;
    style?: StyleProp<ViewStyle>;
};
type IconProps = {
    color?: string;
    size?: number;
};
const Alert = forwardRef<View, AlertProps>(({ children, variant = "default", style, ...props }, ref) => {
    const { theme } = useTheme();
    const { colors, spacing, radius } = THEME[theme];
    const palette = VARIANT_PALETTE[variant];
    const accentColor = variant === "default" ? colors.mutedForeground : palette.accent;
    const bgColor = theme === "dark" ? palette.bgDark : palette.bg;
    const childArray = React.Children.toArray(children);
    const alertSubNames = new Set([
        "AlertTitle",
        "AlertDescription",
        "AlertAction",
    ]);
    let iconChild: React.ReactNode = null;
    let restChildren: React.ReactNode[] = childArray;
    const first = childArray[0] as React.ReactElement | undefined;
    if (first &&
        React.isValidElement(first) &&
        !alertSubNames.has((first.type as any)?.displayName ?? "")) {
        iconChild = first;
        restChildren = childArray.slice(1);
    }
    const iconElement = iconChild as React.ReactElement<IconProps> | null;
    return (<AlertContext.Provider value={{ variant, accentColor }}>
        <View ref={ref} accessibilityRole="alert" {...props} style={[
            styles.root,
            {
                backgroundColor: bgColor,
                borderColor: colors.border,
                borderLeftColor: accentColor,
                borderRadius: radius.lg,
                padding: spacing.lg,
                gap: spacing.xs,
            },
            style,
        ]}>
          <View style={styles.row}>
            {iconElement ? (<View style={[styles.iconSlot, { marginTop: 1 }]}>
                {React.cloneElement(iconElement, {
                color: iconElement.props.color ?? accentColor,
                size: iconElement.props.size ?? 18,
            })}
              </View>) : null}

            <View style={styles.contentColumn}>{restChildren}</View>
          </View>
        </View>
      </AlertContext.Provider>);
});
Alert.displayName = "Alert";
type AlertTitleProps = TextProps & {
    style?: StyleProp<TextStyle>;
};
const AlertTitle = forwardRef<Text, AlertTitleProps>(({ children, style, ...props }, ref) => {
    const { theme } = useTheme();
    const { colors, typography } = THEME[theme];
    return (<Text ref={ref} accessibilityRole="header" {...props} style={[
            styles.title,
            {
                color: colors.foreground,
                fontSize: typography.sm,
            },
            style,
        ]}>
        {children}
      </Text>);
});
AlertTitle.displayName = "AlertTitle";
type AlertDescriptionProps = TextProps & {
    style?: StyleProp<TextStyle>;
};
const AlertDescription = forwardRef<Text, AlertDescriptionProps>(({ children, style, ...props }, ref) => {
    const { theme } = useTheme();
    const { colors, typography, spacing } = THEME[theme];
    return (<Text ref={ref} {...props} style={[
            {
                color: colors.mutedForeground,
                fontSize: typography.xs,
                lineHeight: typography.xs * 1.55,
                marginTop: spacing.xs,
            },
            style,
        ]}>
        {children}
      </Text>);
});
AlertDescription.displayName = "AlertDescription";
type AlertActionProps = ViewProps & {
    style?: StyleProp<ViewStyle>;
};
const AlertAction = forwardRef<View, AlertActionProps>(({ children, style, ...props }, ref) => {
    const { theme } = useTheme();
    const { spacing } = THEME[theme];
    return (<View ref={ref} {...props} style={[{ marginTop: spacing.sm, alignSelf: "flex-start" }, style]}>
        {children}
      </View>);
});
AlertAction.displayName = "AlertAction";
const styles = StyleSheet.create({
    root: {
        borderWidth: 1,
        borderLeftWidth: 4,
    },
    row: {
        flexDirection: "row",
        alignItems: "flex-start",
    },
    iconSlot: {
        marginRight: 12,
        flexShrink: 0,
    },
    contentColumn: {
        flex: 1,
    },
    title: {
        fontWeight: "600",
        letterSpacing: 0.1,
    },
});
export { Alert, AlertAction, AlertDescription, AlertTitle };"
    }
  ]
}

