{
  "$schema": "https://nativeui.qzz.io/schema/registry-item.json",
  "name": "avatar",
  "type": "registry:component",
  "title": "Avatar",
  "description": "Avatar component",
  "registryDependencies": [],
  "dependencies": [],
  "category": "primitives",
  "files": [
    {
      "path": "components/ui/avatar.tsx",
      "type": "registry:component",
      "target": "components/ui/avatar.tsx",
      "content": "import { THEME, useTheme } from "@/lib/theme";
import { forwardRef, useState } from "react";
import { Image, Text, View, type ViewProps } from "react-native";
export const AvatarFallback = forwardRef<View, ViewProps>(({ style, children, ...rest }, ref) => {
    return (<View ref={ref} style={[
            {
                flex: 1,
                width: "100%",
                height: "100%",
                justifyContent: "center",
                alignItems: "center",
            },
            style,
        ]} {...rest}>
        {children}
      </View>);
});
AvatarFallback.displayName = "AvatarFallback";
type AvatarProps = {
    name: string;
    picture?: string;
    size?: number;
    children?: React.ReactNode;
} & Omit<ViewProps, "style">;
const getInitials = (name: string) => {
    const words = name.trim().split(/\s+/);
    if (!words[0])
        return "";
    return words
        .slice(0, 2)
        .map((w) => w[0].toUpperCase())
        .join("");
};
export const Avatar = forwardRef<View, AvatarProps>(({ name, picture, size = 40, accessibilityLabel, children, ...rest }, ref) => {
    const [error, setError] = useState<boolean>(false);
    const { theme } = useTheme();
    const { colors } = THEME[theme];
    const initials = getInitials(name);
    const fontSize = size * 0.35;
    const borderRadius = size / 2;
    const renderFallback = () => {
        if (children) {
            return children;
        }
        return (<Text style={{
                color: colors.primaryForeground,
                fontSize,
                fontWeight: "700",
                letterSpacing: 0.5,
            }} importantForAccessibility="no" accessibilityElementsHidden>
          {initials}
        </Text>);
    };
    return (<View ref={ref} accessibilityRole="image" accessibilityLabel={accessibilityLabel ?? name} {...rest} style={{
            width: size,
            height: size,
            borderRadius,
            backgroundColor: colors.primary,
            justifyContent: "center",
            alignItems: "center",
            overflow: "hidden",
        }}>
        {picture && !error ? (<Image source={{ uri: picture }} style={{ width: size, height: size, borderRadius }} resizeMode="cover" importantForAccessibility="no" accessibilityElementsHidden accessibilityIgnoresInvertColors onError={() => setError(true)}/>) : (renderFallback())}
      </View>);
});
Avatar.displayName = "Avatar";"
    }
  ]
}

{
  "$schema": "https://nativeui.qzz.io/schema/registry-item.json",
  "name": "badge",
  "type": "registry:component",
  "title": "Badge",
  "description": "Badge component",
  "registryDependencies": [],
  "dependencies": [],
  "category": "primitives",
  "files": [
    {
      "path": "components/ui/badge.tsx",
      "type": "registry:component",
      "target": "components/ui/badge.tsx",
      "content": "import { THEME, useTheme } from "@/lib/theme";
import { forwardRef } from "react";
import { Text, View, type ViewStyle, type TextStyle, type StyleProp, type ViewProps, } from "react-native";
type BadgeVariant = "default" | "secondary" | "destructive" | "outline" | "ghost";
type BadgeProps = {
    label: string;
    variant?: BadgeVariant;
    icon?: React.ReactNode;
    style?: StyleProp<ViewStyle>;
    textStyle?: StyleProp<TextStyle>;
} & Omit<ViewProps, "style">;
const Badge = forwardRef<View, BadgeProps>(({ label, variant = "default", icon, style, textStyle, accessibilityLabel, ...rest }, ref) => {
    const { theme } = useTheme();
    const { colors, spacing, radius } = THEME[theme];
    const variantStyles: Record<BadgeVariant, {
        container: ViewStyle;
        text: TextStyle;
    }> = {
        default: {
            container: {
                backgroundColor: colors.primary,
                borderColor: "transparent",
            },
            text: { color: colors.primaryForeground },
        },
        secondary: {
            container: {
                backgroundColor: colors.secondary,
                borderColor: "transparent",
            },
            text: { color: colors.secondaryForeground },
        },
        destructive: {
            container: {
                backgroundColor: colors.destructive,
                borderColor: "transparent",
            },
            text: { color: colors.destructiveForeground },
        },
        outline: {
            container: {
                backgroundColor: "transparent",
                borderColor: colors.border,
            },
            text: { color: colors.foreground },
        },
        ghost: {
            container: {
                backgroundColor: colors.muted,
                borderColor: "transparent",
            },
            text: { color: colors.mutedForeground },
        },
    };
    const { container, text } = variantStyles[variant];
    return (<View ref={ref} accessibilityRole="text" accessibilityLabel={accessibilityLabel ?? label} {...rest} style={[
            {
                flexDirection: "row",
                alignItems: "center",
                alignSelf: "flex-start",
                gap: spacing.xs,
                paddingHorizontal: spacing.sm,
                paddingVertical: 3,
                borderRadius: radius.full,
                borderWidth: 1,
            },
            container,
            style,
        ]}>
        {icon}
        <Text style={[
            { fontSize: 12, fontWeight: "600", letterSpacing: 0.1 },
            text,
