type InputOTPGroupProps = {
    style?: StyleProp<ViewStyle>;
} & Omit<ViewProps, "style">;
type InputOTPSlotProps = {
    index: number;
    style?: StyleProp<ViewStyle>;
    charStyle?: StyleProp<TextStyle>;
} & Omit<ViewProps, "style">;
