const BLINK_ON_MS = 530;
const BLINK_OFF_MS = 430;
const BLINK_FADE_MS = 80;
const InputOTPSlot = forwardRef<View, InputOTPSlotProps>(({ index, style, charStyle, ...rest }, ref) => {
